package com.evolua.content.interfaces.rest; import com.evolua.content.application.TrailService; import com.evolua.content.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/trails") public class TrailController { private final TrailService service; private final TrailMapper mapper; private final CurrentUserProvider currentUserProvider; public TrailController(TrailService service, TrailMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create Trail") public ResponseEntity<ApiResponse<TrailResponse>> create(@Valid @RequestBody TrailRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.title(), request.description(), request.category(), request.premium()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List trails") public ResponseEntity<ApiResponse<List<TrailResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
